function normalizeValidationError(
  error: BatchCreateError | null,
): NormalizedValidationError | null {
  if (!error?.detail) return null;

  const detail = error.detail;
  const files = Array.isArray(detail.files) ? detail.files : [];
  const issues = Array.isArray(detail.issues) ? detail.issues : [];

  if (!files.length && !issues.length) return null;

  const issueLines = issues.map((issue) => {
    const row = typeof issue.row === "number" ? issue.row : "unknown";
    const directory = issue.directory || "unknown directory";
    const promptColumn = issue.prompt_column || "unknown prompt column";
    const imageColumn = issue.image_column || "unknown image column";
    return `Row ${row} (${directory}): prompt column "${promptColumn}" is missing required image in "${imageColumn}"`;
  });

  const items = [...files, ...issueLines];
  const count = typeof detail.count === "number" ? detail.count : items.length;

  return {
    message: detail.error || "Validation error",
    count,
    itemLabel: files.length > 0 && issues.length === 0 ? "missing file(s)" : "issue(s)",
    items,
  };
}

